// KaTeX utils
function escA(s){return s.replace(/&/g,"&amp;").replace(/"/g,"&quot;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}
function inlineP(t){
  t=t.replace(/\$([^$]+)\$/g,(_,l)=>`<span class="mi" data-l="${escA(l)}"></span>`);
  t=t.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>");
  t=t.replace(/\*(.+?)\*/g,"<em>$1</em>");
  t=t.replace(/`([^`]+)`/g,'<code style="background:#0f172a;border:1px solid #334155;padding:1px 5px;border-radius:4px;font-family:monospace;font-size:12px;color:#86efac">$1</code>');
  return t;
}
function mdHtml(text){
  let lines=text.split("\n"),html="",tR=[],inT=false;
  const fT=()=>{if(!tR.length)return"";let t='<table style="width:100%;border-collapse:collapse;margin:8px 0;font-size:12px"><thead><tr>';tR[0].split("|").map(h=>h.trim()).filter(Boolean).forEach(h=>{t+=`<th style="background:#1e3a5f;color:#f59e0b;padding:6px 8px;text-align:left;font-weight:600">${inlineP(h)}</th>`;});t+="</tr></thead><tbody>";for(let r=2;r<tR.length;r++){const cs=tR[r].split("|").map(c=>c.trim()).filter(Boolean);t+="<tr>";cs.forEach((c,i)=>{t+=`<td style="padding:5px 8px;border-bottom:1px solid #1e293b;color:#cbd5e1;${i%2===0?"":"background:rgba(30,41,59,0.4)"}">${inlineP(c)}</td>`;});t+="</tr>";}t+="</tbody></table>";tR=[];return t;};
  for(let i=0;i<lines.length;i++){
    const l=lines[i];
    if(l.trim().startsWith("$$")&&l.trim().endsWith("$$")&&l.trim().length>4){if(inT){html+=fT();inT=false;}html+=`<div class="mb" data-l="${escA(l.trim().slice(2,-2).trim())}"></div>`;continue;}
    if(l.trim()==="$$"){if(inT){html+=fT();inT=false;}let lx="";i++;while(i<lines.length&&lines[i].trim()!=="$$"){lx+=lines[i]+"\n";i++;}html+=`<div class="mb" data-l="${escA(lx.trim())}"></div>`;continue;}
    if(l.includes("|")){inT=true;tR.push(l);continue;}else if(inT){html+=fT();inT=false;}
    if(l.startsWith("### ")){html+=`<h3 style="font-size:13px;font-weight:600;color:#93c5fd;margin:7px 0 3px">${inlineP(l.slice(4))}</h3>`;continue;}
    if(l.startsWith("## ")){html+=`<h2 style="font-size:15px;font-weight:700;color:#fbbf24;margin:9px 0 4px">${inlineP(l.slice(3))}</h2>`;continue;}
    if(l.startsWith("# ")){html+=`<h1 style="font-size:17px;font-weight:700;color:#f59e0b;margin:10px 0 5px;border-bottom:1px solid #1e3a5f;padding-bottom:3px">${inlineP(l.slice(2))}</h1>`;continue;}
    if(l.trim()==="---"){html+='<hr style="border:none;border-top:1px solid #1e3a5f;margin:8px 0"/>';continue;}
    if(l.match(/^[-*] /)){html+=`<div style="padding-left:12px;margin:2px 0;line-height:1.7">• ${inlineP(l.slice(2))}</div>`;continue;}
    if(l.startsWith("> ")){html+=`<div style="border-left:3px solid #f59e0b;padding-left:10px;color:#cbd5e1;margin:5px 0;font-style:italic">${inlineP(l.slice(2))}</div>`;continue;}
    if(l.trim()===""){html+='<div style="height:5px"></div>';continue;}
    html+=`<div style="margin:2px 0;line-height:1.7">${inlineP(l)}</div>`;
  }
  if(inT)html+=fT();
  return html;
}
function renderMath(el){
  if(!window.katex)return;
  el.querySelectorAll(".mb").forEach(e=>{try{window.katex.render(e.getAttribute("data-l"),e,{displayMode:true,throwOnError:false});}catch(ex){e.textContent=e.getAttribute("data-l");}});
  el.querySelectorAll(".mi").forEach(e=>{try{window.katex.render(e.getAttribute("data-l"),e,{displayMode:false,throwOnError:false});}catch(ex){e.textContent=e.getAttribute("data-l");}});
}

function MdBlock({text}){
  const ref=useRef(null);
  const[rdy,setRdy]=useState(!!window.katex);
  useEffect(()=>{if(!window.katex){const c=setInterval(()=>{if(window.katex){setRdy(true);clearInterval(c);}},200);return()=>clearInterval(c);}}, []);
  useEffect(()=>{if(ref.current&&rdy){ref.current.innerHTML=mdHtml(text);renderMath(ref.current);}},[rdy,text]);
  return <span ref={ref}/>;
}

async function callGemini(messages,langInstruction){
  const sys=`You are an expert Electrical Engineering tutor. LANGUAGE (HIGHEST PRIORITY): ${langInstruction} Use KaTeX for ALL formulas: inline $formula$, block $$formula$$. Use markdown: **bold**, ## headings, - bullets, > blockquotes, tables.`;
  const contents=messages.map(m=>({role:m.role==="assistant"?"model":"user",parts:[{text:m.content}]}));
  contents[contents.length-1].parts[0].text=sys+"\n\n"+contents[contents.length-1].parts[0].text;
  const r=await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents})});
  const d=await r.json();
  if(d.error)throw new Error(d.error.message);
  return d.candidates?.[0]?.content?.parts?.[0]?.text||"Error";
}

