function ResistorCalc(){
  const[bands,setBands]=useState(["Brown","Black","Red","Gold"]);
  const cN=Object.keys(COLOR_BANDS),tN=Object.keys(TOLERANCE);
  const res=(()=>{const b1=COLOR_BANDS[bands[0]],b2=COLOR_BANDS[bands[1]],b3=COLOR_BANDS[bands[2]];if(!b1||!b2||!b3)return"?";const v=(b1.v*10+b2.v)*b3.m;return v>=1000000?(v/1000000).toFixed(2)+" MΩ":v>=1000?(v/1000).toFixed(2)+" kΩ":v+" Ω";})();
  return(
    <div style={{padding:"16px"}}>
      <div style={{display:"flex",gap:"8px",marginBottom:"16px",justifyContent:"center"}}>
        {bands.map((b,i)=>(
          <div key={i} style={{textAlign:"center"}}>
            <div style={{width:"28px",height:"60px",borderRadius:"4px",background:i<3?(COLOR_BANDS[b]?.c||"#ccc"):(TOLERANCE[b]?.c||"#ccc"),border:"2px solid rgba(0,0,0,0.3)",margin:"0 auto 4px"}}/>
            <select value={b} onChange={e=>{const nb=[...bands];nb[i]=e.target.value;setBands(nb);}} style={{fontSize:"11px",padding:"2px",borderRadius:"4px",border:"1px solid #334155",background:"#1e293b",color:"#e2e8f0",width:"60px"}}>
              {(i<3?cN:tN).map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
        ))}
      </div>
      <div style={{textAlign:"center",background:"#0f172a",borderRadius:"8px",padding:"12px"}}>
        <div style={{fontSize:"13px",color:"#94a3b8"}}>Resistance</div>
        <div style={{fontSize:"24px",fontWeight:"700",color:"#f59e0b"}}>{res}</div>
        <div style={{fontSize:"13px",color:"#94a3b8"}}>Tolerance: {TOLERANCE[bands[3]]?.v||"?"}</div>
      </div>
    </div>
  );
}

